jsLib:
var FQTT_BASE='https://fq-tt-worker.ch6vip.workers.dev';
var FQTT_BROWSER={isHideable:true,expandedCornersRadius:12,skipCollapsed:true,hardwareAccelerated:true,heightPercentage:0.8};
function fqGetQuery(url,name){var m=String(url||'').match(new RegExp('[?&]'+name+'=([^&#]*)'));return m&&m[1]?decodeURIComponent(m[1]):'';}
function fqPickQuery(urls,names){for(var i=0;i<urls.length;i++)for(var j=0;j<names.length;j++){var v=fqGetQuery(urls[i],names[j]);if(v)return v;}return '';}
function fqFindIdInText(text,names){var s=String(text||'');for(var i=0;i<names.length;i++){var m=s.match(new RegExp(names[i]+'(?:\\"?\\s*[:=]\\s*\\"?|=)([0-9]{6,})','i'));if(m&&m[1])return m[1];}return ''; }
function fqSafeGet(k){try{return String(java.get(k)||'');}catch(e){return '';}}
function fqGetField(obj,names){try{for(var i=0;i<names.length;i++){var v=obj&&obj[names[i]];if(v!==undefined&&v!==null&&String(v)!=='')return String(v);}}catch(e){}return '';}
function fqBase64Decode(input){var chars='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=';var str=String(input||'').replace(/[^A-Za-z0-9+/=]/g,'');var out='',i=0;while(i<str.length){var e1=chars.indexOf(str.charAt(i++)),e2=chars.indexOf(str.charAt(i++)),e3=chars.indexOf(str.charAt(i++)),e4=chars.indexOf(str.charAt(i++));var c1=(e1<<2)|(e2>>4),c2=((e2&15)<<4)|(e3>>2),c3=((e3&3)<<6)|e4;if(e1>=0&&e2>=0)out+=String.fromCharCode(c1);if(e3>=0&&e3!==64)out+=String.fromCharCode(c2);if(e4>=0&&e4!==64)out+=String.fromCharCode(c3);}return out;}
function fqParseMetaText(text){var s=String(text||'');try{return JSON.parse(s);}catch(e){}if(/^\d+$/.test(s))return {item_id:s};return {};}
function fqDecodeDataMeta(url){var m=String(url||'').match(/data:[^,]*;base64,([A-Za-z0-9+/=]+)/i);if(!m||!m[1])return {};var raw='';try{raw=java.hexDecodeToString(m[1]);}catch(e){}if(!raw)raw=fqBase64Decode(m[1]);return fqParseMetaText(raw);}
function fqMetaFromUrls(urls){for(var i=0;i<urls.length;i++){var meta=fqDecodeDataMeta(urls[i]);if(meta&&(meta.book_id||meta.bookId||meta.item_id||meta.itemId||meta.item_ids))return meta;}return {};}
function fqStringifyDeep(obj,depth){var out='';if(depth<0||obj===null||obj===undefined)return out;try{var t=typeof obj;if(t==='string'||t==='number'||t==='boolean')return ' '+obj;for(var k in obj){var v=obj[k];if(v===null||v===undefined)continue;var vt=typeof v;if(vt==='string'||vt==='number'||vt==='boolean')out+=' '+k+'='+v;else if(depth>0)out+=' '+k+' '+fqStringifyDeep(v,depth-1);}}catch(e){}return out;}
function fqCleanParagraphText(text){return String(text||'').replace(/<[^>]+>/g,'').replace(/&nbsp;/g,' ').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&').replace(/^\s+|\s+$/g,'');}
function fqNormalizeTitleText(text){return fqCleanParagraphText(text).replace(/\s+/g,'');}
function fqLooksLocalChapterTitle(text,ctx){var v=fqNormalizeTitleText(text);if(!v||v.length>40)return false;var c=ctx&&ctx.chapter?ctx.chapter:{};var title=fqNormalizeTitleText(c.title||c.name||c.chapterName||c.chapterTitle||ctx.title||'');return !!(title&&(v===title||v.indexOf(title)>=0||title.indexOf(v)>=0));}
function fqSplitLines(text){return String(text||'').replace(/\r/g,'').split('\n');}
function fqHasBubbleMarker(line,bookId,itemId,paraIndex){return String(line||'').indexOf('paragraphRule:fqtt:'+bookId+':'+itemId+':'+paraIndex)>=0;}
function fqParagraphRaw(p){if(p===null||p===undefined)return '';if(typeof p==='string'||typeof p==='number')return String(p);return String(p.content||p.text||p.paragraph||p.value||p.body||'');}
function fqAppendBubbleToParagraph(list,i,bubble){var p=list[i];if(p===null||p===undefined){list[i]=bubble;return;}if(typeof p==='string'||typeof p==='number'){list[i]=String(p)+bubble;return;}if(p.content!==undefined)p.content=String(p.content||'')+bubble;else if(p.text!==undefined)p.text=String(p.text||'')+bubble;else if(p.paragraph!==undefined)p.paragraph=String(p.paragraph||'')+bubble;else if(p.value!==undefined)p.value=String(p.value||'')+bubble;else list[i]=fqParagraphRaw(p)+bubble;}
function fqCommentPageUrl(bookId,itemId,paraIndex){return FQTT_BASE+'/?api=comment_page&book_id='+encodeURIComponent(String(bookId||''))+'&item_id='+encodeURIComponent(String(itemId||''))+'&para_index='+encodeURIComponent(String(paraIndex||'0'))+'&offset=0&count=100';}
function showCmt(bookId,itemId,paraIndex,paraText){java.showBrowser(fqCommentPageUrl(bookId,itemId,paraIndex),null,null,JSON.stringify(FQTT_BROWSER));}
function fqMakeBubble(ruleIdValue,bookId,itemId,paraIndex,paraText){var p=String(paraIndex||'0');var action='showCmt(';var click={style:'TEXT',type:'fq',status:'normal',width:'36',js:'result',pclick:action+JSON.stringify(String(bookId))+','+JSON.stringify(String(itemId))+','+JSON.stringify(p)+','+JSON.stringify(String(paraText||''))+')',marker:'paragraphRule:fqtt:'+bookId+':'+itemId+':'+p};return '<img src="'+FQTT_BASE+'/comment-icon.png,'+JSON.stringify(click)+'">';}

script:
function process(ctx){
  if(!ctx)return null;
  var meta=fqResolveChapterMeta(ctx);
  if(!meta||!meta.bookId||!meta.itemId){try{java.log('fqtt paragraph no bookId/itemId');}catch(e){}return ctx.result||ctx.content||ctx.paragraphs;}
  if(ctx.paragraphs&&ctx.paragraphs.length){return fqProcessParagraphArray(ctx,meta);}
  return fqProcessText(ctx,meta);
}
function fqProcessParagraphArray(ctx,meta){
  var list=ctx.paragraphs;
  var localIndex=0;
  var firstText=true;
  var hits=0;
  for(var i=0;i<list.length;i++){
    var raw=fqParagraphRaw(list[i]);
    var text=fqCleanParagraphText(raw);
    if(!text)continue;
    if(firstText&&fqLooksLocalChapterTitle(text,ctx)){firstText=false;continue;}
    firstText=false;
    var idx=String(localIndex++);
    if(fqHasBubbleMarker(raw,meta.bookId,meta.itemId,idx))continue;
    fqAppendBubbleToParagraph(list,i,fqMakeBubble(fqGetRuleId(ctx),meta.bookId,meta.itemId,idx,text));
    hits++;
  }
  try{java.log('fqtt paragraph array bubbles='+hits+' bookId='+meta.bookId+' itemId='+meta.itemId);}catch(e){}
  return list;
}
function fqProcessText(ctx,meta){
  var lines=fqSplitLines(String(ctx.content||ctx.result||''));
  var localIndex=0;
  var firstText=true;
  var hits=0;
  for(var i=0;i<lines.length;i++){
    var line=String(lines[i]||'');
    var text=fqCleanParagraphText(line);
    if(!text)continue;
    if(firstText&&fqLooksLocalChapterTitle(text,ctx)){firstText=false;continue;}
    firstText=false;
    var idx=String(localIndex++);
    if(fqHasBubbleMarker(line,meta.bookId,meta.itemId,idx))continue;
    lines[i]=line+fqMakeBubble(fqGetRuleId(ctx),meta.bookId,meta.itemId,idx,text);
    hits++;
  }
  try{java.log('fqtt paragraph text bubbles='+hits+' bookId='+meta.bookId+' itemId='+meta.itemId);}catch(e){}
  return lines.join('\n');
}
function fqGetRuleId(ctx){try{return String(ctx&&ctx.rule&&ctx.rule.id||'');}catch(e){return '';}}
function fqResolveChapterMeta(ctx){
  try{
    var chapter=ctx.chapter||{};
    var book=ctx.book||{};
    var urls=[String(chapter.url||''),String(chapter.chapterUrl||''),String(chapter.link||''),String(ctx.baseUrl||''),String(ctx.url||''),String(ctx.chapterUrl||''),String(book.bookUrl||''),String(book.url||''),String(book.tocUrl||'')];
    var dataMeta=fqMetaFromUrls(urls);
    var scanText=urls.join(' ')+' '+fqStringifyDeep(ctx,3)+' '+fqStringifyDeep(chapter,3)+' '+fqStringifyDeep(book,3);
    var itemId=fqGetField(dataMeta,['item_id','itemId','item_ids'])||fqSafeGet('fqtt_item_id')||fqSafeGet('item_id')||fqGetField(chapter,['item_id','itemId','itemIdStr','id'])||fqPickQuery(urls,['item_ids','item_id','itemId','itemid'])||fqFindIdInText(scanText,['item_ids','item_id','itemId','itemid']);
    if(itemId&&itemId.indexOf(',')>=0)itemId=itemId.split(',')[0];
    var bookId=fqGetField(dataMeta,['book_id','bookId','bookid'])||fqSafeGet('fqtt_book_id')||fqSafeGet('book_id')||fqGetField(chapter,['book_id','bookId','bookid'])||fqGetField(book,['book_id','bookId','bookid'])||fqPickQuery(urls,['book_id','bookId','bookid'])||fqFindIdInText(scanText,['book_id','bookId','bookid']);
    return {bookId:String(bookId||''),itemId:String(itemId||'')};
  }catch(e){try{java.log('fqtt paragraph meta failed: '+e);}catch(_e){}return null;}
}
